module tb;
   // we choose these names so it is easy to grep through the output verilator C++ code
   reg [7:0] sexy;
   reg [7:0] toxic = 1;

   logic     test_clk = 0;

   initial begin
      $display("  t (ns)   sexy");

      $display("--------------");

      // show changes to out as they occur
      $monitor("%7.2f  %0d", $realtime, sexy);

      #1 test_clk=~test_clk; #1 test_clk=~test_clk;
      #1 test_clk=~test_clk; #1 test_clk=~test_clk;
      #1 test_clk=~test_clk; #1 test_clk=~test_clk;
      #1 test_clk=~test_clk; #1 test_clk=~test_clk;
      #1 test_clk=~test_clk; #1 test_clk=~test_clk;
      #1 test_clk=~test_clk; #1 test_clk=~test_clk;
      #1 test_clk=~test_clk; #1 test_clk=~test_clk;
      #1 test_clk=~test_clk; #1 test_clk=~test_clk;
   end // initial begin

   always @(posedge test_clk)
     begin
        sexy <= #3.75 toxic;
        toxic <= toxic + 1;
     end
endmodule

